 (Self      : Socket_Class;
  buf       : System.Address;
  len       : Natural;
  count     : OUT Natural)

PROCEDURE Send
 (Self      : Socket_Class;
  buf       : System.Address;
  len       : Natural;
  count     : OUT Natural)

FUNCTION To_Endpoint
 (addr      : String;
